using System;
using System.Reflection;
using SkiaSharp.Views.Maui;

Console.WriteLine("=== SKTouchEventArgs.WheelDelta Investigation ===");
var basic = new SKTouchEventArgs(0, SKTouchAction.WheelChanged, new SkiaSharp.SKPoint(100, 100), false);
Console.WriteLine($"Basic constructor: WheelDelta = {basic.WheelDelta}");
var withWheel = new SKTouchEventArgs(0, SKTouchAction.WheelChanged, SKMouseButton.Unknown, SKTouchDeviceType.Mouse, new SkiaSharp.SKPoint(100, 100), false, 120);
Console.WriteLine($"Full constructor wheelDelta=120: WheelDelta = {withWheel.WheelDelta}");
var androidPattern = new SKTouchEventArgs(0, SKTouchAction.WheelChanged, SKMouseButton.Unknown, SKTouchDeviceType.Mouse, new SkiaSharp.SKPoint(100, 100), false, 0);
Console.WriteLine($"Full constructor wheelDelta=0: WheelDelta = {androidPattern.WheelDelta}");
var prop = typeof(SKTouchEventArgs).GetProperty("WheelDelta");
Console.WriteLine($"WheelDelta: Type={prop?.PropertyType.Name}, CanWrite={prop?.GetSetMethod(false) != null}");
